import{_ as e,o as s,c as t,a2 as o}from"./chunks/framework.BS3ZfcoS.js";const c=JSON.parse('{"title":"付鹏调研","description":"","frontmatter":{"title":"付鹏调研","author":"","collection":"调研报告","series_order":1,"total_chars":6114},"headers":[],"relativePath":"reports/fu-peng-report.md","filePath":"reports/fu-peng-report.md"}'),p={name:"reports/fu-peng-report.md"};function r(h,a,l,i,n,u){return s(),t("div",null,[...a[0]||(a[0]=[o('<div class="page-toc"><p class="page-toc-title">📑 本页目录</p><a href="#s-1" class="page-toc-link">一、基本信息与代表作</a>     <a href="#s-2" class="page-toc-link">1.1 学术背景与职业履历</a>     <a href="#s-3" class="page-toc-link">1.2 代表著作</a>     <a href="#s-4" class="page-toc-link">1.3 传播渠道与影响力</a>     <a href="#s-5" class="page-toc-link">1.4 10年《付鹏说》持续输出记录</a><a href="#s-6" class="page-toc-link">二、核心思想体系梳理</a>     <a href="#s-7" class="page-toc-link">2.1 &quot;三组核心逻辑&quot;完整框架</a>     <a href="#s-11" class="page-toc-link">2.2 &quot;三齿轮框架&quot;详解</a>     <a href="#s-15" class="page-toc-link">2.3 &quot;效率优先→安全优先&quot;范式转换</a>     <a href="#s-16" class="page-toc-link">2.4 最有独创性的5个核心论点</a>     <a href="#s-22" class="page-toc-link">2.5 10年预判记录验证</a><a href="#s-25" class="page-toc-link">三、六维评估</a>     <a href="#s-26" class="page-toc-link">3.1 体系性：5分</a>     <a href="#s-27" class="page-toc-link">3.2 独创性：4分</a>     <a href="#s-28" class="page-toc-link">3.3 闭环度：4分</a>     <a href="#s-29" class="page-toc-link">3.4 可优化性：3分</a>     <a href="#s-30" class="page-toc-link">3.5 内容量：5分</a>     <a href="#s-31" class="page-toc-link">3.6 跨域迁移：3分</a>     <a href="#s-32" class="page-toc-link">3.7 六维综合评分</a><a href="#s-33" class="page-toc-link">四、争议与批评</a>     <a href="#s-34" class="page-toc-link">4.1 预测质疑</a>     <a href="#s-35" class="page-toc-link">4.2 与其他经济学家的争议</a>     <a href="#s-36" class="page-toc-link">4.3 学术严谨性质疑</a>     <a href="#s-37" class="page-toc-link">4.4 辞职风波的舆论解读</a><a href="#s-38" class="page-toc-link">五、萃取价值判断</a>     <a href="#s-39" class="page-toc-link">5.1 付鹏 vs 翟东升（4.17）：谁更值得萃取？</a>     <a href="#s-40" class="page-toc-link">5.2 闭环4分是否意味着可优化空间有限？</a>     <a href="#s-41" class="page-toc-link">5.3 最值得萃取的3个方向</a><a href="#s-45" class="page-toc-link">附录：关键信息汇总</a>     <a href="#s-46" class="page-toc-link">A. 付鹏 vs 同类分析者定位矩阵</a>     <a href="#s-47" class="page-toc-link">B. 付鹏核心时间线</a></div><p>付鹏深度调研报告</p><p>**副标题：**东北证券前首席经济学家 | 宏观分析体系构建者 | 经济周期领域TOP候选</p><p>**初筛六维：**体系5/独创4/闭环4/可优化3/内容5/迁移3 = 综合4.0</p><p>**调研日期：**2026年7月13日</p><h2 id="s-1" tabindex="-1">一、基本信息与代表作 <a class="header-anchor" href="#s-1" aria-label="Permalink to &quot;一、基本信息与代表作 {#s-1}&quot;">​</a></h2><h3 id="s-2" tabindex="-1">1.1 学术背景与职业履历 <a class="header-anchor" href="#s-2" aria-label="Permalink to &quot;1.1 学术背景与职业履历 {#s-2}&quot;">​</a></h3><p>**学历：**英国雷丁大学ISMA/ICMA（国际资本市场协会）中心，主修国际证券、投资与银行学</p><p>**旅居英国：**11年（2000年赴英深造，2008年底回国）</p><p><strong>职业履历：</strong></p><p>**2004年：**就职于英国雷曼兄弟</p><p>**2005-2008年：**所罗门国际投资集团，任国际金融市场全球宏观对冲策略设计主管，参与2008年全球著名对冲基金狙击英镑全过程</p><p>**2008年底：**回国，在多家金融机构担任要职，同时管理一家海外对冲基金</p><p>**2020年2月：**加盟东北证券，出任首席经济学家</p><p>**2023年：**荣获新浪财经最具影响力十大经济学家</p><p>**2025年4月30日：**因身体原因辞去东北证券首席经济学家职务（刚完成两场重大手术），官方回应确因健康原因，非网络传言的&quot;静音事件&quot;</p><p>**2026年4月：**入职新火集团担任首席经济学家，首秀于香港Web3嘉年华，提出FICC+C（加密资产纳入大类资产配置框架）</p><h3 id="s-3" tabindex="-1">1.2 代表著作 <a class="header-anchor" href="#s-3" aria-label="Permalink to &quot;1.2 代表著作 {#s-3}&quot;">​</a></h3><p><strong>《见证逆潮：全球资产逻辑大变局的思考》</strong>（2024年3月出版）</p><p>豆瓣评分8.4，出版3个月重印10次</p><p>被读者评为&quot;国内作者对宏观经济、金融领域写得最好的一本书&quot;</p><p>核心结构：分工与分配→债务与杠杆→收入与贫富，三级分工体系，美债收益率传导机制</p><p>起点中文网有声版上线，超2000集音频内容（含《付鹏说》系列）</p><p>参考体系：达利欧《债务危机》+ 余永定《见证失衡》+ 阿西莫格鲁AGR模型</p><h3 id="s-4" tabindex="-1">1.3 传播渠道与影响力 <a class="header-anchor" href="#s-4" aria-label="Permalink to &quot;1.3 传播渠道与影响力 {#s-4}&quot;">​</a></h3><p>**抖音：**118.7万粉丝（财经类头部账号）</p><p>**微博：**251万粉丝（截至2025年7月）</p><p>**B站：**付鹏的财经世界，多条视频播放10万+</p><p>**华尔街见闻《付鹏说》：**年度专栏连续10年（2017-2026），第六季全面升级，新增社群实时更新</p><p>**雪球：**高频长文输出，多篇演讲实录刷屏</p><p>**央视/新华社/凤凰卫视：**常驻特约财经评论人</p><h3 id="s-5" tabindex="-1">1.4 10年《付鹏说》持续输出记录 <a class="header-anchor" href="#s-5" aria-label="Permalink to &quot;1.4 10年《付鹏说》持续输出记录 {#s-5}&quot;">​</a></h3><p>2017-2026年连续十年，华尔街见闻年度专栏</p><p>2026年进入第六季，新增专栏交流群+实时市场观点+图表数据解读</p><p>内容覆盖：FICC大类资产、全球宏观对冲、产业链传导、AI时代生产关系重构</p><p>年度重磅演讲：长白山论坛（已办4届）、Alpha峰会、各类闭门会</p><h2 id="s-6" tabindex="-1">二、核心思想体系梳理 <a class="header-anchor" href="#s-6" aria-label="Permalink to &quot;二、核心思想体系梳理 {#s-6}&quot;">​</a></h2><h3 id="s-7" tabindex="-1">2.1 &quot;三组核心逻辑&quot;完整框架 <a class="header-anchor" href="#s-7" aria-label="Permalink to &quot;2.1 &quot;三组核心逻辑&quot;完整框架 {#s-7}&quot;">​</a></h3><p>付鹏在《见证逆潮》开篇即明：理解全球宏观经济，无需纠结短期数据波动，抓住三组核心逻辑即可——</p><h4 id="s-8" tabindex="-1">（1）分工与分配 → 财富创造 <a class="header-anchor" href="#s-8" aria-label="Permalink to &quot;（1）分工与分配 → 财富创造 {#s-8}&quot;">​</a></h4><p>分工：分别从事不同又相互联系的工作，资源在不同地区之间的分配</p><p>劳动分工起源于个体才能差异性+交易倾向，优势：提高熟练度、节约切换成本、促进创新</p><p>全球化三级分工体系：核心技术/品牌（高附加值）→ 制造/组装（中附加值）→ 原材料/能源（低附加值）</p><p>分配主导权决定谁拿走最大蛋糕——发达国家掌控分配端，发展中国家被锁定在制造端</p><h4 id="s-9" tabindex="-1">（2）债务与杠杆 → 财富扩张 <a class="header-anchor" href="#s-9" aria-label="Permalink to &quot;（2）债务与杠杆 → 财富扩张 {#s-9}&quot;">​</a></h4><p>金融本质：提供债务和杠杆服务的行业</p><p>宽松刺激政策托底=以推高杠杆和债务积累为代价，不能从根本上解决收入增长和分配问题</p><p>负债的权力：通过大量对外负债拥有消费端力量（美元体系核心逻辑）</p><p>过去40年顶层通胀底层通缩：想变富需掌握债务/通胀/金融资产，底层只靠劳动力=缩</p><h4 id="s-10" tabindex="-1">（3）收入与贫富 → 财富分配 <a class="header-anchor" href="#s-10" aria-label="Permalink to &quot;（3）收入与贫富 → 财富分配 {#s-10}&quot;">​</a></h4><p>K型社会：富人资产膨胀+穷人收入停滞</p><p>收入是支撑债务和杠杆的关键——收入不足则杠杆不可持续</p><p>过剩生产和通胀预期中枢下行→危机爆发</p><p>这三组逻辑相互交织，构成过去几十年全球经济运行主线，也埋下当下危机种子</p><h3 id="s-11" tabindex="-1">2.2 &quot;三齿轮框架&quot;详解 <a class="header-anchor" href="#s-11" aria-label="Permalink to &quot;2.2 &quot;三齿轮框架&quot;详解 {#s-11}&quot;">​</a></h3><p>基于2024年诺贝尔经济学奖得主阿西莫格鲁的AGR模型，延伸出生产力-生产关系-制度秩序的三角互动逻辑：</p><h4 id="s-12" tabindex="-1">齿轮1：生产力（Productivity） <a class="header-anchor" href="#s-12" aria-label="Permalink to &quot;齿轮1：生产力（Productivity） {#s-12}&quot;">​</a></h4><p>技术突变驱动：AI芯片、大模型、算力基建</p><p>2022年底ChatGPT时刻=新一轮生产力革命的起点</p><p>AI基建期（2023-2025）已完成：全球Nvidia/台积电/算力中心投入阶段结束</p><h4 id="s-13" tabindex="-1">齿轮2：生产关系（Production Relations） <a class="header-anchor" href="#s-13" aria-label="Permalink to &quot;齿轮2：生产关系（Production Relations） {#s-13}&quot;">​</a></h4><p>资源分配、分工方式、协作模式的重构</p><p>AI如何改变企业运作、改变消费——生产关系滞后摩擦</p><p>2026年进入&quot;破坏性重构&quot;期：熊彼特式创造性破坏，先干掉老的，再有新的替代</p><h4 id="s-14" tabindex="-1">齿轮3：制度与秩序（Order） <a class="header-anchor" href="#s-14" aria-label="Permalink to &quot;齿轮3：制度与秩序（Order） {#s-14}&quot;">​</a></h4><p>特殊的生产关系：国与国=贸易/金融/安全秩序（基辛格《世界秩序》），企业内=打卡制度等规则</p><p>全要素生产率（TFP）=三齿轮转动效率的量化指标</p><p>**核心论断：**股市是效率的晴雨表，不是经济的晴雨表——长期走势反映TFP，非GDP</p><h3 id="s-15" tabindex="-1">2.3 &quot;效率优先→安全优先&quot;范式转换 <a class="header-anchor" href="#s-15" aria-label="Permalink to &quot;2.3 &quot;效率优先→安全优先&quot;范式转换 {#s-15}&quot;">​</a></h3><p>过去30年全球化：效率优先=谁便宜买谁→深度嵌套、高度分散的生产网络</p><p>现在：安全优先=谁可靠买谁→供应链回旋镖效应、友岸外包、近岸外包</p><p>驱动因素：地缘冲突+疫情暴露脆弱性+技术封锁</p><p>投资含义：提升安全保障的资产表现更好——冲突消耗品/能源/耐用品+安全工业/国防/科技</p><p>全球风险报告已转向：地缘政治对抗&gt;通胀/衰退，经济金融风险退出核心行列</p><h3 id="s-16" tabindex="-1">2.4 最有独创性的5个核心论点 <a class="header-anchor" href="#s-16" aria-label="Permalink to &quot;2.4 最有独创性的5个核心论点 {#s-16}&quot;">​</a></h3><h4 id="s-17" tabindex="-1">1. 股市是TFP的映射，不是GDP的晴雨表 <a class="header-anchor" href="#s-17" aria-label="Permalink to &quot;1. 股市是TFP的映射，不是GDP的晴雨表 {#s-17}&quot;">​</a></h4><p>打破&quot;股市是经济晴雨表&quot;的常识，建立效率-资产的量化逻辑</p><h4 id="s-18" tabindex="-1">2. 三齿轮必须顺次转动才算超级大周期 <a class="header-anchor" href="#s-18" aria-label="Permalink to &quot;2. 三齿轮必须顺次转动才算超级大周期 {#s-18}&quot;">​</a></h4><p>单一技术突破不够，必须生产关系适配→制度秩序适配，否则只有&quot;路没有车&quot;</p><h4 id="s-19" tabindex="-1">3. AI 18个月证伪窗口 <a class="header-anchor" href="#s-19" aria-label="Permalink to &quot;3. AI 18个月证伪窗口 {#s-19}&quot;">​</a></h4><p>2026年是AI&quot;证伪之年&quot;——基建已完，12-18个月内若应用不落地兑现盈利=泡沫</p><h4 id="s-20" tabindex="-1">4. 1%-5%-15%-60%财富分层预言 <a class="header-anchor" href="#s-20" aria-label="Permalink to &quot;4. 1%-5%-15%-60%财富分层预言 {#s-20}&quot;">​</a></h4><p>AI时代生产关系重构后的残酷分层：1%技术掌控者、5%适配者、15%服务者、60%被替代者</p><h4 id="s-21" tabindex="-1">5. &quot;强预期弱现实&quot;范式 <a class="header-anchor" href="#s-21" aria-label="Permalink to &quot;5. &quot;强预期弱现实&quot;范式 {#s-21}&quot;">​</a></h4><p>2023年提出，精准预判全年市场走势——预期打得满但现实兑现不了，A股3000-3300震荡</p><h3 id="s-22" tabindex="-1">2.5 10年预判记录验证 <a class="header-anchor" href="#s-22" aria-label="Permalink to &quot;2.5 10年预判记录验证 {#s-22}&quot;">​</a></h3><h4 id="s-23" tabindex="-1">已验证的关键预判： <a class="header-anchor" href="#s-23" aria-label="Permalink to &quot;已验证的关键预判： {#s-23}&quot;">​</a></h4><p>**2008年：**金融危机正确判断，参与狙击英镑全过程——实战验证</p><p>**2022年11月：**全球化终结，未来5-10年资产定价逻辑改变——后续逆全球化趋势完全印证</p><p><strong>2023年2月：</strong>&quot;强预期弱现实&quot;，A股无牛市、3000-3300震荡——2023年全年走势精准命中</p><p>**2023年2月：**三大高估（美国衰退/欧洲能源/国内恢复）——全部后续数据修正证实</p><p>**2023年：**U型复苏而非V型反弹——消费/地产数据持续走弱验证</p><p>**2025年12月：**AI基建期结束，2026年是证伪之年——2026年DeepSeek等事件部分验证应用落地</p><h4 id="s-24" tabindex="-1">待验证/部分验证的预判： <a class="header-anchor" href="#s-24" aria-label="Permalink to &quot;待验证/部分验证的预判： {#s-24}&quot;">​</a></h4><p>**2026年1月：**12-18个月内AI对生产关系破坏性重构——正在验证中</p><p><strong>2026年：</strong>&quot;股市4000点没跌你赔30%&quot;（权重股撑指数/小微盘杀估值）——2026年上半年部分验证</p><p>**2026年：**AI泡沫若被证明=全球市场崩盘——高风险高赔率预判，尚无定论</p><p>**长期：**1%-5%-15%-60%财富分层——结构性趋势，需5-10年验证</p><h2 id="s-25" tabindex="-1">三、六维评估 <a class="header-anchor" href="#s-25" aria-label="Permalink to &quot;三、六维评估 {#s-25}&quot;">​</a></h2><h3 id="s-26" tabindex="-1">3.1 体系性：5分 <a class="header-anchor" href="#s-26" aria-label="Permalink to &quot;3.1 体系性：5分 {#s-26}&quot;">​</a></h3><p>完整度和自洽性评估：</p><p>底层逻辑：三组核心逻辑（分工/债务/收入）→三齿轮（生产力/生产关系/制度秩序）→范式转换（效率→安全）→资产配置，层层递进</p><p>从《国富论》级根基出发，融合达利欧债务框架+阿西莫格鲁制度模型+康波周期，但形成自己独立体系</p><p>宏观→中观→微观打通：宏观变量→行业传导→哑铃配置，落地到大类资产FICC方法论</p><p>自洽性极高：TFP=效率映射→股市非GDP晴雨表→齿轮顺转=超级周期，逻辑链闭环</p><p>**扣分点：**对货币政策传导的微观机制描述偏弱，制度秩序的量化指标体系不够显性</p><h3 id="s-27" tabindex="-1">3.2 独创性：4分 <a class="header-anchor" href="#s-27" aria-label="Permalink to &quot;3.2 独创性：4分 {#s-27}&quot;">​</a></h3><p>与同类宏观分析者的差异：</p><p>**vs达利欧：**达利欧以债务周期为核心（3个模板×18种情境），付鹏的&quot;三齿轮&quot;比债务周期多出制度秩序维度，且TFP映射论更直接连接资本市场</p><p>**vs周金涛：**周金涛以康波50-60年周期为核心（三周期嵌套），付鹏不依赖固定周期长度，强调齿轮的顺次转动而非时间规律，更具动态性</p><p>**vs洪灏：**洪灏以流动性/850天线为核心，未对AI底层逻辑变化提出新观点，付鹏已完全转向AI时代生产关系分析</p><p>**vs翟东升：**翟东升偏政治经济学（&quot;2超多强&quot;博弈框架），付鹏偏市场实践（对冲基金出身→资产配置落地），两者互补</p><p>**独创核心：**TFP映射论+三齿轮顺转条件+18个月证伪窗口——这三个论点在同类分析者中无直接对应</p><h3 id="s-28" tabindex="-1">3.3 闭环度：4分 <a class="header-anchor" href="#s-28" aria-label="Permalink to &quot;3.3 闭环度：4分 {#s-28}&quot;">​</a></h3><p>看见→判断→行动→验证四步闭环：</p><p>**看见：**10年+持续输出，全球宏观高频跟踪，对冲基金实盘经验提供真实信息源</p><p>**判断：**三齿轮框架+三组核心逻辑提供结构化判断，非拍脑袋——每年2-3次重磅演讲均有框架推演</p><p>**行动：**哑铃配置（底层类现金/红利股+顶层成长股）、FICC大类资产轮动、2026年FICC+C加密资产——可操作</p><p>**验证：**2008狙击英镑/2023强预期弱现实/三大高估——有明确可验证记录</p><p>**扣分点：**验证多在&quot;方向性&quot;层面（对/错），缺少系统性的量化回测框架；部分预判时间窗口偏宽（&quot;12-18个月&quot;）</p><h3 id="s-29" tabindex="-1">3.4 可优化性：3分 <a class="header-anchor" href="#s-29" aria-label="Permalink to &quot;3.4 可优化性：3分 {#s-29}&quot;">​</a></h3><p>空白区域识别：</p><p>**量化缺口：**三齿轮框架目前偏定性，缺少TFP的实时量化指标体系+齿轮转速的量化测度</p><p>**微观传导：**宏观→行业的传导路径描述了（如AI从硬件到应用），但行业→企业→个人的传导链不够细</p><p>**中国制度变量：**对中国制度秩序的特殊性（政策市/国企/金融管制）虽有涉及但未体系化</p><p>**反例/边界条件：**缺少对框架失效条件的系统梳理——什么时候三齿轮不顺转但仍有机会？</p><p>**加密资产：**2026年刚加入FICC+C框架，尚待深化，这是当前最大的增量空间</p><h3 id="s-30" tabindex="-1">3.5 内容量：5分 <a class="header-anchor" href="#s-30" aria-label="Permalink to &quot;3.5 内容量：5分 {#s-30}&quot;">​</a></h3><p>10年内容量与可萃取比例：</p><p>《付鹏说》10年×6季×每日视频+社群更新——估计单视频15-60分钟，年产出300+期</p><p>《见证逆潮》有声版2000+集</p><p>年度长白山论坛+Alpha峰会+闭门会——每年4-6场重磅演讲，单场1-3小时</p><p>雪球长文+微博+B站视频——高频碎片输出</p><p>**可萃取比例：**重磅演讲和专栏干货密度极高（70-80%可萃取），碎片内容约30-40%</p><h3 id="s-31" tabindex="-1">3.6 跨域迁移：3分 <a class="header-anchor" href="#s-31" aria-label="Permalink to &quot;3.6 跨域迁移：3分 {#s-31}&quot;">​</a></h3><p>宏观分析能否迁移到企业/个人决策：</p><p>**企业层面：**三齿轮框架可直接迁移——企业的生产力（技术栈）、生产关系（组织架构）、制度秩序（治理结构），但付鹏本人未展开企业级应用</p><p><strong>个人层面：</strong>&quot;人生三大机遇&quot;论点可迁移（对应三齿轮的三个突破点），但具体到个人职业/投资决策的操作指引偏弱</p><p>**迁移案例：**1%-5%-15%-60%分层→个人如何进入前6%？哑铃配置→个人资产配置，但后者更偏机构级</p><p>**扣分点：**核心面向机构投资者（FICC大类资产），个人理财场景需大量适配工作</p><h3 id="s-32" tabindex="-1">3.7 六维综合评分 <a class="header-anchor" href="#s-32" aria-label="Permalink to &quot;3.7 六维综合评分 {#s-32}&quot;">​</a></h3><h2 id="s-33" tabindex="-1">四、争议与批评 <a class="header-anchor" href="#s-33" aria-label="Permalink to &quot;四、争议与批评 {#s-33}&quot;">​</a></h2><h3 id="s-34" tabindex="-1">4.1 预测质疑 <a class="header-anchor" href="#s-34" aria-label="Permalink to &quot;4.1 预测质疑 {#s-34}&quot;">​</a></h3><p><strong>时间窗口模糊：</strong>&quot;12-18个月&quot;&quot;未来5-10年&quot;等预判时间跨度宽，验证标准不严格——批评者认为这降低了预判的含金量</p><p><strong>AI泡沫预判的极化：</strong>&quot;如果AI是泡沫全球市场都会崩&quot;——这是一个高风险高赔率但几乎不可证伪的命题（若不崩=AI是真的，若崩=他是对的）</p><p>**2024年9月国庆行情：**付鹏未预判924行情的爆发力度，被部分投资者质疑对政策驱动的短期行情把握不足</p><h3 id="s-35" tabindex="-1">4.2 与其他经济学家的争议 <a class="header-anchor" href="#s-35" aria-label="Permalink to &quot;4.2 与其他经济学家的争议 {#s-35}&quot;">​</a></h3><p>**vs看多方：**2023年敢于作为券商首席看空A股（&quot;今年不要有6000点不是梦的想法&quot;），在券商中极为罕见，引发业内争议</p><p>**vs汇丰：**曾怒怼汇丰陷入舆情风波（具体内容未公开）</p><p>**vs&quot;网红经济学家&quot;标签：**被冠以&quot;网红&quot;身份，部分传统学术圈质疑其学术深度——但《见证逆潮》豆瓣8.4分和实操战绩部分回应了此质疑</p><h3 id="s-36" tabindex="-1">4.3 学术严谨性质疑 <a class="header-anchor" href="#s-36" aria-label="Permalink to &quot;4.3 学术严谨性质疑 {#s-36}&quot;">​</a></h3><p>无顶级学术期刊论文发表（非学术路线出身），框架偏&quot;实践智慧&quot;而非&quot;学术理论&quot;</p><p>三齿轮框架引用阿西莫格鲁2024诺奖背书，但自己的延伸论证缺少学术论文形式验证</p><p>&quot;网红首席&quot;身份的双刃剑：传播力强但学术圈接受度受限——2023年春季策略会演讲结束，1/6观众追着他走，这既是影响力也被视为&quot;追星&quot;非&quot;追智&quot;</p><p>**反驳：**10年对冲基金实盘+2008狙击英镑的实战记录，是学术圈纸面研究无法替代的验证</p><h3 id="s-37" tabindex="-1">4.4 辞职风波的舆论解读 <a class="header-anchor" href="#s-37" aria-label="Permalink to &quot;4.4 辞职风波的舆论解读 {#s-37}&quot;">​</a></h3><p>2025年4月30日辞职，官方=身体原因（刚完成两场重大手术），界面新闻确认与网络传言无关</p><p>但金融圈广泛流传&quot;他的嘴比他的病更让某些人头疼&quot;的版本——付鹏多次直言中国经济问题</p><p>引发&quot;经济学家成为敏感词&quot;讨论：当&quot;健康原因&quot;成为离职高频词，是否意味经济学界自我审查时代降临？</p><h2 id="s-38" tabindex="-1">五、萃取价值判断 <a class="header-anchor" href="#s-38" aria-label="Permalink to &quot;五、萃取价值判断 {#s-38}&quot;">​</a></h2><h3 id="s-39" tabindex="-1">5.1 付鹏 vs 翟东升（4.17）：谁更值得萃取？ <a class="header-anchor" href="#s-39" aria-label="Permalink to &quot;5.1 付鹏 vs 翟东升（4.17）：谁更值得萃取？ {#s-39}&quot;">​</a></h3><p>**结论：**两者互补而非替代。付鹏强在市场端（体系性5+内容量5+实盘闭环），翟东升强在政策端（迁移5+可优化4+学术深度）。</p><p>**萃取优先级：**若目标=宏观投资决策框架→付鹏优先；若目标=政经分析+国际博弈→翟东升优先。综合建议：两者均萃取，付鹏偏&quot;术&quot;（资产配置方法论），翟东升偏&quot;道&quot;（底层权力逻辑）。</p><h3 id="s-40" tabindex="-1">5.2 闭环4分是否意味着可优化空间有限？ <a class="header-anchor" href="#s-40" aria-label="Permalink to &quot;5.2 闭环4分是否意味着可优化空间有限？ {#s-40}&quot;">​</a></h3><p>**否。**闭环度和可优化性评估的是不同维度：</p><p>闭环度=看见→判断→行动→验证的链路完整度——付鹏在&quot;方向性验证&quot;上强，但缺少&quot;量化验证&quot;</p><p>可优化性=现有框架的空白区域——付鹏的5个空白（量化指标/微观传导/中国制度/反例边界/FICC+C）恰好是闭环度提升的方向</p><p>**关键洞察：**闭环4+可优化3=正好说明&quot;框架方向对但精细化不足&quot;——这是最优萃取状态，因为可优化的方向明确且有框架约束，不会变成无边际的猜测</p><p>对比：若闭环5+可优化1=框架已精化到极致，萃取反而边际递减；若闭环2+可优化5=框架散乱，萃取困难</p><h3 id="s-41" tabindex="-1">5.3 最值得萃取的3个方向 <a class="header-anchor" href="#s-41" aria-label="Permalink to &quot;5.3 最值得萃取的3个方向 {#s-41}&quot;">​</a></h3><h4 id="s-42" tabindex="-1">方向1：三齿轮框架的量化化 <a class="header-anchor" href="#s-42" aria-label="Permalink to &quot;方向1：三齿轮框架的量化化 {#s-42}&quot;">​</a></h4><p>目标：将TFP→齿轮转速→资产价格的定性框架，转化为可量化、可跟踪的指标体系</p><p>价值：这是付鹏体系最大的空白，填补后可将&quot;方向性预判&quot;升级为&quot;量化信号&quot;</p><p>可行性：TFP已有索洛余值法测算基础，齿轮转速可用PMI/产能利用率/制度指数近似</p><h4 id="s-43" tabindex="-1">方向2：AI时代产业传导路径 <a class="header-anchor" href="#s-43" aria-label="Permalink to &quot;方向2：AI时代产业传导路径 {#s-43}&quot;">​</a></h4><p>目标：从付鹏的&quot;硬件→应用&quot;传导框架出发，细化到行业→企业→岗位的传导链</p><p>价值：1%-5%-15%-60%分层是宏观判断，需要中观/微观的操作化——哪些行业先被重构？哪些岗位先被替代？</p><p>可行性：付鹏已有&quot;企业生命周期看AI产业链&quot;（付鹏说20）的起始框架</p><h4 id="s-44" tabindex="-1">方向3：FICC+C大类资产配置方法论 <a class="header-anchor" href="#s-44" aria-label="Permalink to &quot;方向3：FICC+C大类资产配置方法论 {#s-44}&quot;">​</a></h4><p>目标：将传统FICC（外汇/利率/信用/商品）+加密资产的综合配置框架系统化</p><p>价值：2026年4月付鹏刚加入新火集团提出FICC+C，这是最前沿且空白最大的方向</p><p>可行性：付鹏25年传统金融经验+对冲基金实操=FICC端已成熟，C端需快速深化</p><h2 id="s-45" tabindex="-1">附录：关键信息汇总 <a class="header-anchor" href="#s-45" aria-label="Permalink to &quot;附录：关键信息汇总 {#s-45}&quot;">​</a></h2><h3 id="s-46" tabindex="-1">A. 付鹏 vs 同类分析者定位矩阵 <a class="header-anchor" href="#s-46" aria-label="Permalink to &quot;A. 付鹏 vs 同类分析者定位矩阵 {#s-46}&quot;">​</a></h3><h3 id="s-47" tabindex="-1">B. 付鹏核心时间线 <a class="header-anchor" href="#s-47" aria-label="Permalink to &quot;B. 付鹏核心时间线 {#s-47}&quot;">​</a></h3><p>2000 赴英深造 → 2004 雷曼兄弟 → 2005-08 所罗门对冲基金（狙击英镑）→ 2008 回国</p><p>2017 《付鹏说》开栏 → 2020 东北证券首席 → 2023 新浪十大经济学家</p><p>2024.3 《见证逆潮》出版 → 2025.4 辞职（健康原因）→ 2025.12 Alpha峰会（三齿轮论）</p><p>2026.3 长白山论坛（AI生产关系重构）→ 2026.4 新火集团首席经济学家首秀（FICC+C）</p><p>**报告完。**本报告基于公开信息整理，截至2026年7月13日。</p>',190)])])}const d=e(p,[["render",r]]);export{c as __pageData,d as default};
